import re

from .generic import apply_rules

DEFAULT_RULES = {
    re.compile(r"(?:o힄ciach|o힄ciami|o힄ciom)$"): "o힄훶",  # removed: "o힄ci훳", "o힄ci"
    re.compile(
        r"(?:owa흢em|owa흢am|owali힄my|owa흢e힄|owa흢a힄|owali힄cie|owa흢bym|owa흢abym|owaliby힄my|owa흢by힄|owa흢aby힄|owaliby힄cie|owa흢by|owa흢aby|owa흢oby|owaliby|owa흢yby|owanie)$"
    ): "owa훶",
    re.compile(r"(?:o힄ciach|o힄ciami|o힄ciom)$"): "o힄훶",
    # re.compile(r"(?:skie|skiego|skiemu|skiej|skich|skim|skimi|sk훳|scy)$"): "ski",
    re.compile(r"(?:aliby힄cie|aliby힄my)$"): "a훶",
    re.compile(r"(?:i흢yby힄cie|iliby힄cie|iliby힄my|i흢yby힄my)$"): "i훶",
    re.compile(r"(?:y흢yby힄cie|yliby힄cie|yliby힄my|y흢yby힄my)$"): "y훶",
}


def apply_pl(token: str) -> str | None:
    "Apply pre-defined rules for Polish."
    if len(token) < 10 or token[0].isupper():
        return None

    return apply_rules(token, DEFAULT_RULES)
